"use client"

import { useState } from "react"
import { useTranslations } from "@/lib/i18n/context"

const experiences = [
  {
    year: "2019",
    period: "2019 - Present",
    title: "Project Management Officer",
    company: "Atradius",
    description: "Facilitated cross-functional collaboration with project managers, ensuring on-time and on-budget project delivery. Optimized resource planning, mitigated risks and managed dependencies, standardized governance frameworks, and organized project documentation."
  },
  {
    year: "2018",
    period: "2018 - 2019",
    title: "Project Coordinator",
    company: "Tata Steel",
    description: "Designed and coordinated training programs, managed project tasks and dependencies across multiple initiatives. Facilitated cross-department communication acting as key liaison for Sales, Marketing, and Supply Chain teams."
  },
  {
    year: "2017",
    period: "2017 - 2018",
    title: "Team Leader",
    company: "Hotel Specials",
    description: "Implemented quality improvement initiatives, reducing error rates and increasing customer satisfaction scores. Coached and mentored a team of 10+ advisors, improving performance and team efficiency."
  },
  {
    year: "2015",
    period: "2015 - 2018",
    title: "Flight Attendant",
    company: "Menzies Schiphol Airport",
    description: "Assisted passengers with check-in, boarding, and luggage handling while ensuring compliance with airline procedures."
  },
  {
    year: "2012",
    period: "2012 - 2015",
    title: "Commercial Customer Advisor",
    company: "Hotel Specials",
    description: "Managed reservations and administrative tasks, ensuring customer satisfaction. Resolved customer complaints and served as the central communication point for queries."
  },
  {
    year: "2010",
    period: "2010 - 2012",
    title: "Management Assistant",
    company: "Tata Steel",
    description: "Provided general departmental support by managing agendas, coordinating meetings, handling incoming calls, and welcoming visitors."
  }
]

interface ExperienceSectionProps {
  currentPage?: number
}

export function ExperienceSection({ currentPage = 4 }: ExperienceSectionProps) {
  const [selectedIndex, setSelectedIndex] = useState(0)
  const [hoveredIndex, setHoveredIndex] = useState<number | null>(null)
  const t = useTranslations()

  return (
    <section id="resume" className="min-h-screen bg-background py-20 px-8">
      <div className="max-w-6xl mx-auto">
        <div className="grid lg:grid-cols-3 gap-12">
          {/* Timeline */}
          <div className="lg:col-span-2">
            <h2 className="text-primary text-3xl font-bold mb-12">{t.experience.title}</h2>
            
            <div className="relative">
              <div className="space-y-0">
                {experiences.map((exp, index) => {
                  const isSelected = selectedIndex === index
                  const isHovered = hoveredIndex === index
                  const isFilled = isSelected || isHovered

                  return (
                    <div 
                      key={index} 
                      className="flex items-stretch group"
                      onClick={() => setSelectedIndex(index)}
                      onMouseEnter={() => setHoveredIndex(index)}
                      onMouseLeave={() => setHoveredIndex(null)}
                    >
                      {/* Year Column */}
                      <div className="w-20 flex-shrink-0 flex items-start pt-1">
                        <span className={`font-semibold transition-colors text-right w-full ${
                          isFilled ? "text-primary" : "text-primary/60"
                        }`}>
                          {exp.year}
                        </span>
                      </div>
                      
                      {/* Timeline Column - Dot and Line */}
                      <div className="w-16 flex-shrink-0 flex flex-col items-center relative mx-4">
                        {/* Line above dot */}
                        {index > 0 && (
                          <div className="w-0.5 bg-primary/60 h-4" />
                        )}
                        {index === 0 && <div className="h-4" />}
                        
                        {/* Dot - larger size */}
                        <div 
                          className={`w-7 h-7 rounded-full border-2 border-primary flex-shrink-0 relative z-10 transition-all duration-200 ${
                            isFilled 
                              ? "bg-primary" 
                              : "bg-background"
                          }`}
                        >
                          {isFilled && (
                            <div className="absolute inset-1.5 rounded-full bg-background/30" />
                          )}
                        </div>
                        
                        {/* Line below dot */}
                        {index < experiences.length - 1 && (
                          <div className="w-0.5 bg-primary/60 flex-1" />
                        )}
                        {index === experiences.length - 1 && <div className="flex-1" />}
                      </div>
                      
                      {/* Content Column */}
                      <div className="flex-1 pb-8">
                        <span className="text-muted-foreground text-sm">{exp.period}</span>
                        <h3 className={`font-semibold mt-1 transition-colors ${
                          isFilled ? "text-foreground" : "text-foreground/80"
                        }`}>
                          {exp.title}
                        </h3>
                        <p className="text-primary text-sm mb-2">{exp.company}</p>
                        <p className={`text-sm leading-relaxed transition-all ${
                          isFilled ? "text-muted-foreground" : "text-muted-foreground/70"
                        }`}>
                          {exp.description}
                        </p>
                      </div>
                    </div>
                  )
                })}
              </div>
            </div>
          </div>

          {/* Cover Letter / Professional Summary */}
          <div className="lg:col-span-1">
            <h2 className="text-primary text-3xl font-bold mb-6">{t.experience.coverLetter}</h2>
            <p className="text-foreground/80 text-lg leading-relaxed mb-6">
              Results-driven Project Management Officer with over 14 years of experience 
              supporting complex, global projects in fast-paced environments.
            </p>
            <p className="text-muted-foreground leading-relaxed mb-6">
              Skilled in risk management, governance, milestone tracking, and stakeholder 
              coordination. Known for enabling project success through structured support, 
              clear communication, and proactive problem solving.
            </p>
            <p className="text-muted-foreground leading-relaxed mb-6">
              Experienced in facilitating cross-functional collaboration, optimizing resource 
              planning, and standardizing governance frameworks to ensure compliance with 
              project management processes.
            </p>
            <p className="text-muted-foreground leading-relaxed">
              Strong background in customer service and team leadership, with proven ability 
              to improve performance, reduce error rates, and increase customer satisfaction 
              through quality improvement initiatives.
            </p>
          </div>
        </div>

        {/* Page Number */}
        <div className="mt-20">
          <div className="text-9xl font-bold text-primary/20">
            {String(currentPage).padStart(2, "0")}
          </div>
        </div>
      </div>
    </section>
  )
}
